class ODT {
private:
	struct ODT_Node {
		ll l, r;
		mutable int v; // 区间是否加入集合 

		// 重载小于号以用于 set 排序
		bool operator<(const ODT_Node& a)const {
			return l < a.l;
		}
	};

	// ODT 的核心操作：分裂区间
	// 将包含 pos 的区间 [l, r] 分裂为 [l, pos - 1] 和 [pos, r]
	// 返回指向后半段 [pos, r] 的迭代器
	auto split(ll pos) {
		auto it = se.lower_bound({ pos, 0, 0 });
		if (it != se.end() and it->l == pos)return it;

		it = prev(it);
		auto [l, r, v] = *it;
		se.erase(it);
		se.insert({ l, pos - 1, v });

		return se.insert({ pos, r, v }).first;
	}

public:
	set<ODT_Node> se;

	// 操作 1、2（推平）
	void assign12(ll l, ll r, int v) {
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;
			it = se.erase(it); // 删除旧区间
		}

		// 插入新区间
		se.insert({ l, r, v });
	}

	// 操作 3（无推平）
	void assign3(ll l, ll r) {
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			it->v ^= 1;
			it = next(it);
		}
	}

	// 查询（可推平）
	ll query(ll l, ll r) {
		auto itr = split(r + 1);
		auto itl = split(l);

		auto it = itl;
		ll L = l;
		while (it != itr) {
			auto [l, r, v] = *it;
			if (v == 0) {
				if(L <= l - 1)se.insert({ L, l - 1, 1 });
				return l;
			}
			it = se.erase(it);
		}
	}
};

void solve(int CASE)
{
	int n; cin >> n;
	var odt = ODT();
	odt.se.insert({ 1, (ll)1e18 + 1, 0 });
	fa(i, 1, n) {
		ll t, l, r; cin >> t >> l >> r;
		if (t == 1)odt.assign12(l, r, 1);
		else if (t == 2)odt.assign12(l, r, 0);
		else odt.assign3(l, r);
		cout << odt.query(1, (ll)1e18) << endl;
	}
	return;
}
